// Validación y preparación de parámetros
const items = $input.first().json.body;
const outputItems = [];

  try {
    // Obtener parámetros del webhook o usar valores por defecto
    const email = items.email || 'admin@example.com';
    const format = items.format || 'ambos';
    const useRange = items.use_range || false;
    const startDate = items.start_date;
    const endDate = items.end_date;
    // Validar formato
    const validFormats = ['pdf', 'xml', 'ambos'];
    if (!validFormats.includes(format)) {
      throw new Error(`Formato inválido: ${format}. Valores permitidos: ${validFormats.join(', ')}`);
    }

    // Validar email
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(email)) {
      throw new Error(`Email inválido: ${email}`);
    }

    // Validar fechas si se usa rango
    if (useRange) {
      if (!startDate || !endDate) {
        throw new Error('start_date y end_date son requeridos cuando use_range es true');
      }

      const start = new Date(startDate);
      const end = new Date(endDate);

      if (isNaN(start.getTime()) || isNaN(end.getTime())) {
        throw new Error('Formato de fecha inválido. Use YYYY-MM-DD');
      }

      if (start > end) {
        throw new Error('start_date debe ser anterior a end_date');
      }
    }

    outputItems.push({
      json: {
        email,
        format,
        use_range: useRange,
        start_date: startDate,
        end_date: endDate,
        validated: true,
        timestamp: new Date().toISOString()
      }
    });

  } catch (error) {
    outputItems.push({
      json: {
        error: error.message,
        validated: false,
        timestamp: new Date().toISOString()
      }
    });
  }


return outputItems;

// Verificar respuesta de la API y extraer cep_id
const items = $input.all();
const outputItems = [];

for (const item of items) {
  try {
    const response = item.json;

    // Validar que la respuesta tenga el formato esperado
    if (!response.cep_id) {
      throw new Error('Respuesta inválida: falta cep_id');
    }

    if (response.status !== 'pending') {
      throw new Error(`Estado inesperado: ${response.status}`);
    }

    outputItems.push({
      json: {
        cep_id: response.cep_id,
        status: response.status,
        message: response.message,
        started_at: new Date().toISOString(),
        poll_count: 0,
        max_polls: 60, // Máximo 60 intentos (10 minutos si poll cada 10s)
        success: true
      }
    });

  } catch (error) {
    outputItems.push({
      json: {
        error: error.message,
        success: false,
        timestamp: new Date().toISOString()
      }
    });
  }
}

return outputItems;

// Analizar estado y decidir siguiente acción
const items = $input.all();
const outputItems = [];

for (const item of items) {
  try {
    const statusResponse = item.json;
    const previousData = $('Process API Response').first().json;

    const pollCount = (previousData.poll_count || 0) + 1;
    const maxPolls = previousData.max_polls || 60;

    let nextAction = 'continue_polling';
    let shouldContinue = true;

    // Determinar acción según estado
    if (statusResponse.status === 'completed') {
      nextAction = 'download';
      shouldContinue = false;
    } else if (statusResponse.status === 'failed') {
      nextAction = 'error';
      shouldContinue = false;
    } else if (pollCount >= maxPolls) {
      nextAction = 'timeout';
      shouldContinue = false;
    }

    outputItems.push({
      json: {
        cep_id: statusResponse.cep_id,
        status: statusResponse.status,
        created_at: statusResponse.created_at,
        completed_at: statusResponse.completed_at,
        records_processed: statusResponse.records_processed,
        token: statusResponse.token,
        download_available: statusResponse.download_available,
        error: statusResponse.error,
        poll_count: pollCount,
        max_polls: maxPolls,
        next_action: nextAction,
        should_continue_polling: shouldContinue,
        elapsed_time_seconds: pollCount * 10
      }
    });

  } catch (error) {
    outputItems.push({
      json: {
        error: error.message,
        next_action: 'error',
        should_continue_polling: false
      }
    });
  }
}

return outputItems;

// Preparar datos para notificación de éxito
const items = $input.all();
const outputItems = [];

for (const item of items) {
  const cepData = $('Analyze Status').first().json;

  outputItems.push({
    json: {
      status: 'success',
      cep_id: cepData.cep_id,
      records_processed: cepData.records_processed,
      token: cepData.token,
      completed_at: cepData.completed_at,
      elapsed_time: `${cepData.elapsed_time_seconds} segundos`,
      download_url: `https://purple-bell-graduated-satisfactory.trycloudflare.com/api/v1/ceps/download/${cepData.cep_id}`,
      message: `✅ CEP generado exitosamente. ${cepData.records_processed} registros procesados.`,
      timestamp: new Date().toISOString()
    }
  });
}

return outputItems;

// Preparar datos para notificación de error
const items = $input.all();
const outputItems = [];

for (const item of items) {
  const data = item.json;

  let errorMessage = '❌ Error en generación de CEP';
  let errorDetails = {};

  if (data.next_action === 'timeout') {
    errorMessage = '⏱️ Timeout: El proceso excedió el tiempo máximo de espera';
    errorDetails = {
      cep_id: data.cep_id,
      poll_count: data.poll_count,
      elapsed_time: `${data.elapsed_time_seconds} segundos`,
      last_status: data.status
    };
  } else if (data.next_action === 'error' || data.error) {
    errorMessage = `❌ Error: ${data.error || 'Error desconocido'}`;
    errorDetails = {
      cep_id: data.cep_id,
      status: data.status,
      error: data.error
    };
  } else if (!data.validated) {
    errorMessage = `⚠️ Validación fallida: ${data.error}`;
    errorDetails = {
      error: data.error
    };
  }

  outputItems.push({
    json: {
      status: 'error',
      message: errorMessage,
      details: errorDetails,
      timestamp: new Date().toISOString()
    }
  });
}

return outputItems;

